questions.solution:
suspend fun <T> retryWithBackoff(
    maxRetries: Int = 3,
    initialDelayMs: Long = 1000,
    onAttempt: (attempt: Int, maxAttempts: Int) -> Unit = { _, _ -> },
    block: suspend () -> T
): T {
    var currentDelay = initialDelayMs
    repeat(maxRetries - 1) { attempt ->
        onAttempt(attempt + 1, maxRetries)
        try {
            return block()
        } catch (e: CancellationException) {
            throw e // NEVER swallow cancellation
        } catch (e: Exception) {
            delay(currentDelay) // Cancellation-aware wait
            currentDelay *= 2
        }
    }
    onAttempt(maxRetries, maxRetries)
    return block() // Final attempt — let it throw
}

